/* ===== SAPPHIRE COURT — premium runtime re-skin ===== */

/* Base typography + ink */
html, body, #root {
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif !important;
  color: #1B2A45 !important;
}
body {
  background-color: #F7F9FC !important;
}

/* Kill gradients for flat premium surfaces */
.bg-gradient-to-br, .bg-gradient-to-r, .bg-gradient-to-b {
  background-image: none !important;
}

/* Display headings — Inter, tight + confident */
h1, h2, h3, h4,
.text-2xl, .text-3xl, .text-4xl, .text-5xl {
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif !important;
  font-weight: 700 !important;
  letter-spacing: -0.02em !important;
  color: #15233B !important;
}

/* Mono uppercase microlabels */
.uppercase {
  font-family: 'JetBrains Mono', ui-monospace, 'SFMono-Regular', monospace !important;
  letter-spacing: 0.1em !important;
  font-weight: 600 !important;
  font-size: 0.68rem !important;
  color: #5B6B85 !important;
}

/* Progressive ink ramp */
.text-gray-900 { color: #14213A !important; }
.text-gray-800 { color: #1E2D49 !important; }
.text-gray-700 { color: #34425E !important; }
.text-gray-600 { color: #4E5C76 !important; }
.text-gray-500 { color: #6B7892 !important; }
.text-gray-400 { color: #93A0B6 !important; }

/* Hairline borders */
[class*="border-gray-"] {
  border-color: #E3E8F0 !important;
}

/* Neutral surfaces */
.bg-gray-50  { background-color: #F2F5FA !important; }
.bg-gray-100 { background-color: #EAEFF6 !important; }
.bg-white    { background-color: #FFFFFF !important; }

/* Card system */
.card {
  background: #FFFFFF !important;
  border: 1px solid #E3E8F0 !important;
  border-radius: 14px !important;
  box-shadow: 0 1px 2px rgba(21, 35, 59, 0.04), 0 6px 18px rgba(21, 35, 59, 0.05) !important;
}

/* Radius normalization */
.rounded-md  { border-radius: 9px !important; }
.rounded-lg  { border-radius: 12px !important; }
.rounded-xl  { border-radius: 14px !important; }
.rounded-2xl { border-radius: 16px !important; }

/* Soft shadow normalization */
.shadow, .shadow-sm, .shadow-md, .shadow-lg, .shadow-xl, .shadow-2xl {
  box-shadow: 0 1px 2px rgba(21, 35, 59, 0.04), 0 6px 18px rgba(21, 35, 59, 0.05) !important;
}

/* Dashboard hero numerals — Newsreader serif */
.card .text-2xl, .card .text-3xl {
  font-family: 'Newsreader', Georgia, 'Times New Roman', serif !important;
  font-size: 2.2rem !important;
  font-weight: 500 !important;
  letter-spacing: -0.01em !important;
  color: #15233B !important;
}

/* Card microlabels — mono uppercase muted */
.card .text-sm.font-medium, .card .text-xs {
  font-family: 'JetBrains Mono', ui-monospace, monospace !important;
  text-transform: uppercase !important;
  letter-spacing: 0.08em !important;
  font-size: 0.66rem !important;
  font-weight: 600 !important;
  color: #6B7892 !important;
}
.card h2, .card h3 {
  font-family: 'Inter', sans-serif !important;
}

/* Inputs */
input, select, textarea {
  font-family: 'Inter', sans-serif !important;
}

/* ===== TOP BAR ===== */
header {
  background: #FFFFFF !important;
  border-bottom: 1px solid #E3E8F0 !important;
  box-shadow: none !important;
}
header h2 {
  font-family: 'Inter', sans-serif !important;
  color: #15233B !important;
  font-weight: 700 !important;
}
header button {
  border-radius: 10px !important;
}

/* ===== SIDEBAR — light, sectioned ===== */
#root .fixed.inset-y-0.left-0[class*="bg-[#011E41]"] {
  background: #FFFFFF !important;
  border-right: 1px solid #E3E8F0 !important;
  box-shadow: none !important;
}

/* Section group labels */
#root .fixed.inset-y-0.left-0 [class*="uppercase"] {
  font-family: 'JetBrains Mono', ui-monospace, monospace !important;
  letter-spacing: 0.12em !important;
  font-size: 0.62rem !important;
  font-weight: 600 !important;
  color: #8493AC !important;
  margin-top: 16px !important;
  padding-top: 13px !important;
  border-top: 1px solid #EAEFF6 !important;
}

/* Nav items */
#root .fixed.inset-y-0.left-0 a {
  font-family: 'Inter', sans-serif !important;
  font-size: 0.875rem !important;
  font-weight: 500 !important;
  border-radius: 9px !important;
